<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Maze Explorer</title>
<style>
  *{margin:0;padding:0;box-sizing:border-box}
  body{background:#0d1117;color:#c9d1d9;font-family:system-ui,sans-serif;display:flex;flex-direction:column;align-items:center;padding:12px;min-height:100vh}
  #completed{font-size:20px;margin:6px 0;color:#58a6ff}
  #timer{font-size:20px;margin:6px 0;color:#3fb950}
  #reset{margin:8px 0;padding:9px 22px;font-size:15px;cursor:pointer;background:#da3633;color:#fff;border:none;border-radius:6px;font-weight:600}
  #reset:hover{background:#f85149}
  #maze{position:relative}
  canvas{display:block;border-radius:4px;box-shadow:0 0 20px rgba(0,0,0,.5)}
</style>
</head>
<body>
<div id="completed">Completed: 0 / 24</div>
<div id="timer">Timer: 0</div>
<button id="reset">Reset</button>
<div id="maze"><canvas id="canvas"></canvas></div>
<script>
(function(){
"use strict";

/* ── PRNG (Mulberry32) ── */
function mulberry32(a){
  return function(){
    a|=0; a=(a+0x6D2B79F5)|0;
    var t=Math.imul(a^(a>>>15),1|a);
    t=(t+Math.imul(t^(t>>>7),61|t))^t;
    return((t^(t>>>14))>>>0)/4294967296;
  };
}

/* ── Constants ── */
const ROWS=21, COLS=21, CELL=20, SZ=CELL*ROWS, NBOTS=24, TICK_MS=70;

const DIRS=[
  {dr:-1,dc:0,wall:'n',opp:'s'},
  {dr:0,dc:1,wall:'e',opp:'w'},
  {dr:1,dc:0,wall:'s',opp:'n'},
  {dr:0,dc:-1,wall:'w',opp:'e'}
];

/* ── Maze generation (iterative recursive-backtracker) ── */
function genMaze(rng){
  var walls=[];
  for(var r=0;r<ROWS;r++){walls[r]=[];for(var c=0;c<COLS;c++) walls[r][c]={n:1,e:1,s:1,w:1};}
  var vis=Array.from({length:ROWS},function(){return Array(COLS).fill(0);});
  var stk=[{r:0,c:0}]; vis[0][0]=1;
  while(stk.length){
    var cur=stk[stk.length-1];
    var nbr=[];
    for(var i=0;i<DIRS.length;i++){
      var d=DIRS[i], nr=cur.r+d.dr, nc=cur.c+d.dc;
      if(nr>=0&&nr<ROWS&&nc>=0&&nc<COLS&&!vis[nr][nc]) nbr.push({r:nr,c:nc,d:d});
    }
    if(nbr.length){
      var ch=nbr[Math.floor(rng()*nbr.length)];
      walls[cur.r][cur.c][ch.d.wall]=0;
      walls[ch.r][ch.c][ch.d.opp]=0;
      vis[ch.r][ch.c]=1;
      stk.push({r:ch.r,c:ch.c});
    } else { stk.pop(); }
  }
  return walls;
}

/* ── Bot factory ── */
function makeBot(idx,rng,sp){
  var ord=['n','e','s','w'];
  for(var i=ord.length-1;i>0;i--){var j=Math.floor(rng()*(i+1));var t=ord[i];ord[i]=ord[j];ord[j]=t;}
  var key=sp.r+','+sp.c;
  return {
    cur:{r:sp.r,c:sp.c},
    vis:new Set([key]),
    cw:new Map(),
    stk:[{r:sp.r,c:sp.c}],
    dead:[],
    path:[{r:sp.r,c:sp.c}],
    finish:null,
    ord:ord,
    pr:sp.r,pc:sp.c,cr:sp.r,cc:sp.c
  };
}

/* ── Game state ── */
var maze=null, bots=[], elapsed=0, done=false;
var spawn={r:0,c:0}, exit={r:ROWS-1,c:COLS-1};
var rng=null;

/* ── Tick one bot ── */
function tickBot(bot,t){
  if(bot.finish!==null) return;
  var r=bot.cur.r, c=bot.cur.c, key=r+','+c;
  if(!bot.cw.has(key)) bot.cw.set(key,{n:!!maze[r][c].n,e:!!maze[r][c].e,s:!!maze[r][c].s,w:!!maze[r][c].w});
  if(r===exit.r&&c===exit.c){bot.finish=t;return;}
  var w=bot.cw.get(key);
  for(var i=0;i<bot.ord.length;i++){
    var dn=bot.ord[i];
    for(var j=0;j<DIRS.length;j++){
      if(DIRS[j].wall===dn){
        var d=DIRS[j];
        if(!w[d.wall]){
          var nr=r+d.dr, nc=c+d.dc, nk=nr+','+nc;
          if(!bot.vis.has(nk)){
            bot.pr=bot.cr; bot.pc=bot.cc;
            bot.cr=nr; bot.cc=nc;
            bot.cur={r:nr,c:nc};
            bot.vis.add(nk);
            bot.path.push({r:nr,c:nc});
            bot.stk.push({r:nr,c:nc});
            return;
          }
        }
        break;
      }
    }
  }
  if(bot.stk.length>1){
    bot.dead.push({r:bot.cur.r,c:bot.cur.c});
    bot.stk.pop();
    var pv=bot.stk[bot.stk.length-1];
    bot.pr=bot.cr; bot.pc=bot.cc;
    bot.cr=pv.r; bot.cc=pv.c;
    bot.cur={r:pv.r,c:pv.c};
    bot.path.push({r:pv.r,c:pv.c});
  }
}

/* ── Public API ── */
var game={
  get size(){return{rows:ROWS,cols:COLS};},
  get spawn(){return{r:spawn.r,c:spawn.c};},
  get exit(){return{r:exit.r,c:exit.c};},
  get elapsed(){return elapsed;},
  get bots(){
    return bots.map(function(b){
      return{
        path:b.path.map(function(p){return{r:p.r,c:p.c};}),
        deadEnds:b.dead.map(function(p){return{r:p.r,c:p.c};}),
        finishTick:b.finish
      };
    });
  },
  walls:function(r,c){
    if(maze&&r>=0&&r<ROWS&&c>=0&&c<COLS) return{n:!!maze[r][c].n,e:!!maze[r][c].e,s:!!maze[r][c].s,w:!!maze[r][c].w};
    return{n:1,e:1,s:1,w:1};
  },
  tick:function(n){
    if(done) return;
    for(var i=0;i<n;i++){
      if(done) break;
      elapsed++;
      for(var j=0;j<bots.length;j++) tickBot(bots[j],elapsed);
      if(bots.every(function(b){return b.finish!==null;})) done=true;
    }
  },
  reset:function(seed){
    if(typeof seed==='number') rng=mulberry32(seed);
    else rng=mulberry32(Math.floor(Math.random()*4294967296));
    maze=genMaze(rng);
    bots=[];
    var sk=spawn.r+','+spawn.c;
    for(var i=0;i<NBOTS;i++){
      var b=makeBot(i,rng,spawn);
      b.cw.set(sk,{n:!!maze[spawn.r][spawn.c].n,e:!!maze[spawn.r][spawn.c].e,s:!!maze[spawn.r][spawn.c].s,w:!!maze[spawn.r][spawn.c].w});
      bots.push(b);
    }
    elapsed=0; done=false;
    updUI();
  }
};
window.game=game;

/* ── Rendering ── */
var cv=document.getElementById('canvas');
cv.width=SZ; cv.height=SZ;
var cx=cv.getContext('2d');

var bCol=[];
for(var i=0;i<NBOTS;i++){
  var h=(i*360/NBOTS)%360;
  bCol.push('hsl('+h+',85%,58%)');
}

var aProg=0, lastT=0;

function drawMaze(){
  cx.fillStyle='#0d1117';
  cx.fillRect(0,0,SZ,SZ);
  for(var r=0;r<ROWS;r++){
    for(var c=0;c<COLS;c++){
      var x=c*CELL, y=r*CELL;
      cx.fillStyle='#161b22';
      cx.fillRect(x,y,CELL,CELL);
      var w=maze[r][c];
      cx.strokeStyle='#30363d';
      cx.lineWidth=2;
      if(w.n){cx.beginPath();cx.moveTo(x,y);cx.lineTo(x+CELL,y);cx.stroke();}
      if(w.e){cx.beginPath();cx.moveTo(x+CELL,y);cx.lineTo(x+CELL,y+CELL);cx.stroke();}
      if(w.s){cx.beginPath();cx.moveTo(x,y+CELL);cx.lineTo(x+CELL,y+CELL);cx.stroke();}
      if(w.w){cx.beginPath();cx.moveTo(x,y);cx.lineTo(x,y+CELL);cx.stroke();}
    }
  }
  /* spawn */
  cx.fillStyle='rgba(56,139,253,0.35)';
  cx.fillRect(spawn.c*CELL+1,spawn.r*CELL+1,CELL-2,CELL-2);
  /* exit */
  cx.fillStyle='rgba(248,81,73,0.35)';
  cx.fillRect(exit.c*CELL+1,exit.r*CELL+1,CELL-2,CELL-2);
}

function drawBots(p){
  for(var i=0;i<bots.length;i++){
    var b=bots[i];
    var rr=b.pr+(b.cr-b.pr)*p;
    var cc=b.pc+(b.cc-b.pc)*p;
    var x=cc*CELL+CELL/2;
    var y=rr*CELL+CELL/2;
    cx.beginPath();
    cx.arc(x,y,4.5,0,Math.PI*2);
    cx.fillStyle=bCol[i];
    cx.fill();
    cx.strokeStyle='rgba(255,255,255,0.5)';
    cx.lineWidth=1;
    cx.stroke();
  }
}

function render(){
  drawMaze();
  drawBots(aProg);
}

function updUI(){
  var n=bots.filter(function(b){return b.finish!==null;}).length;
  document.getElementById('completed').textContent='Completed: '+n+' / '+NBOTS;
  document.getElementById('timer').textContent='Timer: '+elapsed;
}

/* ── Animation loop ── */
function anim(ts){
  if(!lastT) lastT=ts;
  var dt=ts-lastT;
  if(!done){
    aProg+=dt/TICK_MS;
    if(aProg>=1){
      game.tick(1);
      aProg=0;
      lastT=ts;
      updUI();
    }
  }
  render();
  requestAnimationFrame(anim);
}

document.getElementById('reset').addEventListener('click',function(){
  game.reset();
  aProg=0; lastT=0;
});

game.reset();
requestAnimationFrame(anim);

})();
</script>
</body>
</html>
